@startuml
title LIGHT's Class Diagram

skinparam packageStyle rectangle
skinparam shadowing false
skinparam classAttributeIconSize 0

package "android" {
  package "view" {
    class "View" as android_view_View {
      class "OnClickListener" as android_view_View_OnClickListener
    }
  }

  package "widget" {
    class "CompoundButton" as android_widget_CompoundButton {
      class "OnCheckedChangeListener" as android_widget_CompoundButton_OnCheckedChangeListener
    }
  }
}

package "androidx" {
  package "appcompat" {
    package "app" {
      class "AppCompatActivity" as androidx_appcompat_app_AppCompatActivity
    }
  }
}

package "com" {
  package "example" {
    package "light" {
      class "BuildConfig" as com_example_light_BuildConfig
      class "MainActivity" as com_example_light_MainActivity
    }
  }
}

com_example_light_MainActivity ..|> android_view_View_OnClickListener
com_example_light_MainActivity ..|> android_widget_CompoundButton_OnCheckedChangeListener
com_example_light_MainActivity --|> androidx_appcompat_app_AppCompatActivity

@enduml
